import React, { useState, useRef, useEffect } from "react";

const LOGO_SRC = "data:image/png;base64,";
const QR_SRC = "data:image/png;base64,";

const PLANE_SRC = "data:image/png;base64,";

const ROLES = [
  "Flight Controller",
  "Budget Controller",
  "Route Planner",
  "Hotel Scout",
  "Local Spotter",
];

const YEARS = Array.from({ length: 11 }, (_, i) => String(2026 + i));

// Brand palette
const C = {
  blueDark: "#1F3A5F",
  blueMid: "#2F5F8F",
  blueLight: "#6FA3C8",
  goldMain: "#D4A73C",
  goldLight: "#F2D27A",
  goldDark: "#A67C1B",
  green: "#6B8E4E",
  sand: "#E6C98A",
};

const CARD_W = 600;
const CARD_H = 1020;

export default function TWFMembershipCard() {
  const [firstName, setFirstName] = useState("");
  const [lastName, setLastName] = useState("");
  const [role, setRole] = useState(ROLES[0]);
  const [memberSince, setMemberSince] = useState("2026");
  const canvasRef = useRef(null);
  const logoImgRef = useRef(null);
  const qrImgRef = useRef(null);
  const planeImgRef = useRef(null);
  const [assetsReady, setAssetsReady] = useState(false);

  useEffect(() => {
    const link = document.createElement("link");
    link.rel = "stylesheet";
    link.href =
      "https://fonts.googleapis.com/css2?family=Anton&family=Bebas+Neue&family=Montserrat:wght@500;600;700&family=Cardo:ital,wght@0,400;0,700;1,400&display=swap";
    document.head.appendChild(link);

    let loaded = 0;
    const checkDone = () => {
      loaded += 1;
      if (loaded === 3) setAssetsReady(true);
    };

    const logoImg = new Image();
    logoImg.onload = () => {
      logoImgRef.current = logoImg;
      checkDone();
    };
    logoImg.src = LOGO_SRC;

    const qrImg = new Image();
    qrImg.onload = () => {
      qrImgRef.current = qrImg;
      checkDone();
    };
    qrImg.src = QR_SRC;

    const planeImg = new Image();
    planeImg.onload = () => {
      planeImgRef.current = planeImg;
      checkDone();
    };
    planeImg.src = PLANE_SRC;

    return () => document.head.removeChild(link);
  }, []);

  const roundRect = (ctx, x, y, w, h, r) => {
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.arcTo(x + w, y, x + w, y + h, r);
    ctx.arcTo(x + w, y + h, x, y + h, r);
    ctx.arcTo(x, y + h, x, y, r);
    ctx.arcTo(x, y, x + w, y, r);
    ctx.closePath();
  };

  const fitText = (ctx, text, maxWidth, baseSize, fontBuilder, minSize) => {
    let size = baseSize;
    ctx.font = fontBuilder(size);
    while (ctx.measureText(text).width > maxWidth && size > minSize) {
      size -= 1;
      ctx.font = fontBuilder(size);
    }
    return size;
  };

  const drawCard = (canvas, scale) => {
    const W = CARD_W * scale;
    const H = CARD_H * scale;
    canvas.width = W;
    canvas.height = H;
    const ctx = canvas.getContext("2d");
    const cx = W / 2;

    // Background
    ctx.fillStyle = C.blueDark;
    roundRect(ctx, 0, 0, W, H, 30 * scale);
    ctx.fill();

    // Outer gold border
    ctx.strokeStyle = C.goldMain;
    ctx.lineWidth = 5 * scale;
    roundRect(ctx, 7 * scale, 7 * scale, W - 14 * scale, H - 14 * scale, 26 * scale);
    ctx.stroke();

    // Inner dashed white border
    ctx.strokeStyle = "rgba(255,255,255,0.85)";
    ctx.lineWidth = 1.5 * scale;
    ctx.setLineDash([3 * scale, 5 * scale]);
    roundRect(ctx, 22 * scale, 22 * scale, W - 44 * scale, H - 44 * scale, 18 * scale);
    ctx.stroke();
    ctx.setLineDash([]);

    // Watermark logo (original colors, subtle, centered on the whole card)
    if (logoImgRef.current) {
      const lw = W * 0.62;
      const lh = lw * (logoImgRef.current.height / logoImgRef.current.width);
      ctx.save();
      ctx.globalAlpha = 0.08;
      ctx.drawImage(logoImgRef.current, cx - lw / 2, H / 2 - lh / 2, lw, lh);
      ctx.restore();
    }

    // Title
    ctx.textAlign = "center";
    ctx.textBaseline = "alphabetic";
    ctx.fillStyle = "#FFFFFF";
    const titleSize = fitText(
      ctx,
      "TOGETHER WE FLY",
      W - 90 * scale,
      48 * scale,
      (s) => "400 " + s + 'px "Anton", sans-serif',
      24 * scale
    );
    const titleWidth = ctx.measureText("TOGETHER WE FLY").width;
    ctx.fillText("TOGETHER WE FLY", cx, 108 * scale);

    // Divider + plane row (lines span exactly the title width)
    const lineY = 148 * scale;
    const planeHalf = 20 * scale;
    ctx.strokeStyle = C.goldMain;
    ctx.lineWidth = 1.4 * scale;
    ctx.beginPath();
    ctx.moveTo(cx - titleWidth / 2, lineY);
    ctx.lineTo(cx - planeHalf - 12 * scale, lineY);
    ctx.moveTo(cx + planeHalf + 12 * scale, lineY);
    ctx.lineTo(cx + titleWidth / 2, lineY);
    ctx.stroke();
    drawPlane(ctx, cx, lineY, planeHalf * 2.4);

    // Slogan
    ctx.fillStyle = "#FFFFFF";
    ctx.font = '400 ' + (20 * scale) + 'px Cardo, serif';
    ctx.fillText("Plan Together. Fly Together.", cx, 200 * scale);

    // Name / Surname
    const first = (firstName || "Name").toUpperCase();
    const last = (lastName || "Surname").toUpperCase();
    ctx.fillStyle = "#FFFFFF";
    const nameMaxWidth = W - 90 * scale;
    const firstSize = fitText(ctx, first, nameMaxWidth, 46 * scale, (s) => "400 " + s + 'px "Bebas Neue", sans-serif', 22 * scale);
    ctx.fillText(first, cx, 398 * scale);
    const lastSize = fitText(ctx, last, nameMaxWidth, 46 * scale, (s) => "400 " + s + 'px "Bebas Neue", sans-serif', 22 * scale);
    ctx.fillText(last, cx, 458 * scale);

    // Role pill
    const roleText = role.toUpperCase();
    ctx.font = '700 ' + (22 * scale) + 'px Cardo, serif';
    const roleTextWidth = ctx.measureText(roleText).width;
    const pillW = roleTextWidth + 64 * scale;
    const pillH = 54 * scale;
    const pillX = cx - pillW / 2;
    const pillY = 510 * scale;
    ctx.fillStyle = C.goldMain;
    roundRect(ctx, pillX, pillY, pillW, pillH, 12 * scale);
    ctx.fill();
    ctx.fillStyle = C.blueDark;
    ctx.fillText(roleText, cx, pillY + pillH / 2 + 8 * scale);

    // Member since
    const memberY = 632 * scale;
    const memberText = "MEMBER SINCE " + (memberSince || "2026");
    ctx.font = '700 ' + (16 * scale) + 'px Cardo, serif';
    const memberWidth = ctx.measureText(memberText).width;
    ctx.strokeStyle = "rgba(212,167,60,0.8)";
    ctx.lineWidth = 1.2 * scale;
    ctx.beginPath();
    ctx.moveTo(cx - memberWidth / 2, memberY - 22 * scale);
    ctx.lineTo(cx + memberWidth / 2, memberY - 22 * scale);
    ctx.stroke();
    ctx.fillStyle = C.goldLight;
    ctx.fillText(memberText, cx, memberY);
    ctx.beginPath();
    ctx.moveTo(cx - memberWidth / 2, memberY + 14 * scale);
    ctx.lineTo(cx + memberWidth / 2, memberY + 14 * scale);
    ctx.stroke();

    // QR box
    const qrBoxSize = 168 * scale;
    const qrBoxX = cx - qrBoxSize / 2;
    const qrBoxY = H - 230 * scale;
    ctx.fillStyle = "#FFFFFF";
    roundRect(ctx, qrBoxX, qrBoxY, qrBoxSize, qrBoxSize, 14 * scale);
    ctx.fill();
    ctx.strokeStyle = C.goldMain;
    ctx.lineWidth = 3 * scale;
    roundRect(ctx, qrBoxX, qrBoxY, qrBoxSize, qrBoxSize, 14 * scale);
    ctx.stroke();
    if (qrImgRef.current) {
      const pad = 14 * scale;
      ctx.drawImage(qrImgRef.current, qrBoxX + pad, qrBoxY + pad, qrBoxSize - pad * 2, qrBoxSize - pad * 2);
    }

    ctx.textAlign = "left";
  };

  const drawPlane = (ctx, cx, cy, size) => {
    if (!planeImgRef.current) return;
    const img = planeImgRef.current;
    const w = size;
    const h = size * (img.height / img.width);
    ctx.drawImage(img, cx - w / 2, cy - h / 2, w, h);
  };

  useEffect(() => {
    if (canvasRef.current && assetsReady) drawCard(canvasRef.current, 1);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [firstName, lastName, role, memberSince, assetsReady]);

  const handleDownloadPNG = () => {
    const exportCanvas = document.createElement("canvas");
    drawCard(exportCanvas, 2.5);
    const link = document.createElement("a");
    link.download = "TWF-card-" + (lastName || "member").toLowerCase() + ".png";
    link.href = exportCanvas.toDataURL("image/png");
    link.click();
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        background: "#FBF7EE",
        fontFamily: "Montserrat, sans-serif",
        padding: "32px 16px",
      }}
    >
      <div style={{ maxWidth: 1040, margin: "0 auto" }}>
        <div style={{ marginBottom: 28, display: "flex", alignItems: "center", gap: 16 }}>
          <img src={LOGO_SRC} alt="Together We Fly" style={{ width: 56, height: 56, objectFit: "contain" }} />
          <div>
            <p
              style={{
                fontFamily: '"Bebas Neue", sans-serif',
                color: C.blueDark,
                fontWeight: 400,
                fontSize: 18,
                letterSpacing: 3,
                margin: 0,
                marginBottom: 4,
              }}
            >
              TOGETHER WE FLY
            </p>
            <h1
              style={{
                fontFamily: "Cardo, serif",
                fontStyle: "italic",
                fontSize: 28,
                fontWeight: 400,
                color: C.blueDark,
                margin: 0,
              }}
            >
              Generate your membership card
            </h1>
          </div>
        </div>

        <div
          style={{
            display: "grid",
            gridTemplateColumns: "minmax(280px, 340px) 1fr",
            gap: 32,
            alignItems: "start",
          }}
        >
          {/* FORM */}
          <div
            style={{
              background: C.goldLight,
              borderRadius: 16,
              padding: 24,
              boxShadow: "0 1px 3px rgba(31,58,95,0.15)",
              border: "1px solid " + C.goldDark,
            }}
          >
            <Field label="Name">
              <input
                style={inputStyle}
                value={firstName}
                onChange={(e) => setFirstName(e.target.value)}
                placeholder="Paolo"
              />
            </Field>
            <Field label="Surname">
              <input
                style={inputStyle}
                value={lastName}
                onChange={(e) => setLastName(e.target.value)}
                placeholder="Rossi"
              />
            </Field>
            <Field label="Role">
              <select style={inputStyle} value={role} onChange={(e) => setRole(e.target.value)}>
                {ROLES.map((r) => (
                  <option key={r} value={r}>
                    {r}
                  </option>
                ))}
              </select>
            </Field>
            <Field label="Member since">
              <select style={inputStyle} value={memberSince} onChange={(e) => setMemberSince(e.target.value)}>
                {YEARS.map((y) => (
                  <option key={y} value={y}>
                    {y}
                  </option>
                ))}
              </select>
            </Field>

            <button onClick={handleDownloadPNG} style={btnStyle(C, true)}>
              Save as PNG
            </button>
          </div>

          {/* CARD PREVIEW */}
          <div style={{ display: "flex", justifyContent: "center" }}>
            <canvas
              ref={canvasRef}
              style={{
                width: "100%",
                maxWidth: 360,
                aspectRatio: (CARD_W / CARD_H).toString(),
                borderRadius: 22,
                boxShadow: "0 12px 40px rgba(31,58,95,0.3)",
              }}
            />
          </div>
        </div>
      </div>
    </div>
  );
}

const inputStyle = {
  width: "100%",
  boxSizing: "border-box",
  padding: "11px 14px",
  borderRadius: 9,
  border: "1px solid #B98F2A",
  fontSize: 15,
  fontFamily: "Montserrat, sans-serif",
  color: "#1F3A5F",
  outline: "none",
  marginBottom: 18,
  background: "#FFFFFF",
};

const btnStyle = (C, primary) => ({
  width: "100%",
  boxSizing: "border-box",
  display: "block",
  textAlign: "center",
  textDecoration: "none",
  marginTop: primary ? 12 : 10,
  background: primary ? C.blueDark : "#FFFFFF",
  color: primary ? "#F2D27A" : C.blueDark,
  border: primary ? "none" : "1.5px solid " + C.blueDark,
  borderRadius: 10,
  padding: "13px 0",
  fontWeight: 700,
  fontSize: 14,
  cursor: "pointer",
  letterSpacing: 0.5,
});

function Field({ label, children }) {
  return (
    <div>
      <label
        style={{
          display: "block",
          fontSize: 12,
          fontWeight: 700,
          letterSpacing: 1,
          color: "#5C4A12",
          marginBottom: 6,
          textTransform: "uppercase",
        }}
      >
        {label}
      </label>
      {children}
    </div>
  );
}
